/**
 * Bundle template files into JS modules for Cloudflare Workers.
 * Workers can't use node:fs at runtime, so we serialize files at build time.
 *
 * Generates:
 *   server/generated/templateFiles.js  — template source files
 *   server/generated/distFiles.js      — pre-built dist files
 */

import { readdir, readFile, writeFile, mkdir, access } from 'node:fs/promises'
import { join, relative, extname, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const SERVER_DIR = join(__dirname, '..')
const TEMPLATE_DIR = join(SERVER_DIR, 'template')
const DIST_DIR = join(TEMPLATE_DIR, 'dist')
const OUT_DIR = join(SERVER_DIR, 'generated')

const BINARY_EXTENSIONS = new Set([
  '.png', '.jpg', '.jpeg', '.gif', '.ico', '.webp', '.avif',
  '.mp4', '.webm', '.mov',
  '.woff', '.woff2', '.ttf', '.eot',
  '.zip', '.tar', '.gz',
])

function isBinary(filePath) {
  return BINARY_EXTENSIONS.has(extname(filePath).toLowerCase())
}

async function walkDir(dir, baseDir) {
  const results = []
  const entries = await readdir(dir, { withFileTypes: true })
  for (const entry of entries) {
    const fullPath = join(dir, entry.name)
    if (entry.isDirectory()) {
      if (['node_modules', '.git', '.github', 'dist'].includes(entry.name)) continue
      results.push(...await walkDir(fullPath, baseDir))
    } else {
      const relPath = relative(baseDir, fullPath)
      const binary = isBinary(fullPath)
      const content = await readFile(fullPath)
      results.push({
        path: relPath,
        content: binary ? content.toString('base64') : content.toString('utf-8'),
        isBinary: binary,
      })
    }
  }
  return results
}

async function main() {
  await mkdir(OUT_DIR, { recursive: true })

  // Bundle template source files
  console.log('[bundle] Reading template source files...')
  const sourceFiles = await walkDir(TEMPLATE_DIR, TEMPLATE_DIR)
  const sourceModule = `// Auto-generated by scripts/bundle-templates.js — do not edit\nexport default ${JSON.stringify(sourceFiles, null, 2)};\n`
  await writeFile(join(OUT_DIR, 'templateFiles.js'), sourceModule)
  console.log(`[bundle] Wrote ${sourceFiles.length} template source files`)

  // Bundle dist files
  try {
    await access(DIST_DIR)
  } catch {
    console.error('[bundle] ERROR: template/dist/ not found. Run "npm run build" in server/ first.')
    process.exit(1)
  }

  console.log('[bundle] Reading dist files...')
  const distFiles = await walkDir(DIST_DIR, DIST_DIR)
  const distModule = `// Auto-generated by scripts/bundle-templates.js — do not edit\nexport default ${JSON.stringify(distFiles, null, 2)};\n`
  await writeFile(join(OUT_DIR, 'distFiles.js'), distModule)
  console.log(`[bundle] Wrote ${distFiles.length} dist files`)
}

main().catch((err) => {
  console.error('[bundle] Fatal error:', err)
  process.exit(1)
})
